using System;
using AzureMcp.Areas.Server.Models;
using AzureMcp.Areas.Server.Options;
using AzureMcp.Areas.Server.Commands.Discovery;
using Xunit;

namespace AzureMcp.Tests
{
    public class SseRemovalTests
    {
        [Fact]
        public void TransportTypes_ShouldNotContainSSE()
        {
            // Test that TransportTypes class does not contain SSE constant
            Assert.Contains("stdio", TransportTypes.StdIo);

            // SSE should not be present in TransportTypes
            var transportType = typeof(TransportTypes);
            var fields = transportType.GetFields();
            Assert.All(fields, field =>
            {
                Assert.NotEqual("Sse", field.Name);
                Assert.NotEqual("sse", field.GetValue(null)?.ToString());
            });
        }

        [Fact]
        public void RegistryServerInfo_ShouldNotSupportUrlProperty()
        {
            // Test that RegistryServerInfo does not have Url property for SSE
            var serverInfo = new RegistryServerInfo();

            var properties = typeof(RegistryServerInfo).GetProperties();
            Assert.All(properties, prop =>
            {
                Assert.NotEqual("Url", prop.Name);
            });
        }

        [Fact]
        public void RegistryServerProvider_ShouldNotCreateSseClient()
        {
            // Test that RegistryServerProvider does not support SSE transport
            var serverInfo = new RegistryServerInfo
            {
                Type = "stdio",
                Command = "echo",
                Args = new List<string> { "test" }
            };

            var provider = new RegistryServerProvider("test", serverInfo);

            // Should create stdio client without SSE support
            var metadata = provider.CreateMetadata();
            Assert.NotNull(metadata);

            // Test that provider does not handle URL-based servers
            var sseServerInfo = new RegistryServerInfo
            {
                Url = "https://example.com/api"
            };

            var sseProvider = new RegistryServerProvider("sse-test", sseServerInfo);

            // Should throw exception when trying to create client with URL
            var options = new ModelContextProtocol.Client.McpClientOptions();
            Assert.ThrowsAny<Exception>(() => sseProvider.CreateClientAsync(options).Result);
        }

        [Fact]
        public void ServiceCollectionExtensions_ShouldNotConfigureSSETransport()
        {
            // Test that service collection extension does not configure SSE transport
            var options = new ServiceStartOptions
            {
                Transport = "stdio",
                Mode = ModeTypes.NamespaceProxy
            };

            var services = new ServiceCollection();
            services.AddAzureMcpServer(options);

            // Should only configure stdio transport
            Assert.Equal("stdio", options.Transport);
            Assert.NotEqual("sse", options.Transport);
        }

        [Fact]
        public void RegistryJson_ShouldNotContainSSEConfigurations()
        {
            // Test that registry.json does not contain URL-based SSE configurations
            // This test verifies that only stdio configurations are present

            var assembly = typeof(RegistryServerInfo).Assembly;
            var resourceName = assembly.GetManifestResourceNames()
                .FirstOrDefault(n => n.EndsWith("registry.json", StringComparison.OrdinalIgnoreCase));

            Assert.NotNull(resourceName);

            using var stream = assembly.GetManifestResourceStream(resourceName)!;
            using var reader = new StreamReader(stream);
            var jsonContent = reader.ReadToEnd();

            // Should not contain URL fields for SSE
            Assert.DoesNotContain("\"url\":", jsonContent);

            // Should only contain stdio configurations
            Assert.Contains("\"type\":", jsonContent);
            Assert.Contains("\"command\":", jsonContent);
        }
    }
}

